---

## 8 · Feasibility matrix

| Change | Effort | Mechanism |
|---|---|---|
| Grid chrome (bg, borders, zebra, hover, selection, accent) | ✅ Cheap | theme param |
| Header colors, font weight/size | ✅ Cheap | theme param |
| Header text uppercase | ✅ Cheap | ::ng-deep |
| Header row heights | ✅ Cheap | ::ng-deep |
| Group-band tints (2-family) | ✅ Cheap | ::ng-deep + headerGroupClass |
| Seam shadow + rule | ✅ Cheap | ::ng-deep `.ag-cell-last-left-pinned` |
| Row group row color fix | ✅ Cheap | ::ng-deep `.ag-full-width-row` |
| Scenario cell tints | ✅ Cheap | cellClass + ::ng-deep |
| Re-quote cell color update | ✅ Cheap | update existing ::ng-deep rule |
| Toolbar button radius/color | ✅ Cheap | SCSS update on existing classes |
| Toolbar dividers | ✅ Cheap | HTML + SCSS |
| Status bar polish | ✅ Cheap | component SCSS |
| Sub-grid flex sizing | ✅ Cheap | colDef `flex` + remove `sizeColumnsToFit` |
| Density toggle | ⚙️ Medium | new UI control + `setGridOption` + localStorage |
| Frozen identity default (new users) | ⚙️ Medium | update Default GridLayout record in DB |
| Frozen identity backfill (existing users) | ⚙️ Medium | `applyColumnState` on `firstDataRendered` |
| Status pill cell renderer | ⚙️ Medium | new `ICellRendererAngularComp` |
| Step indicator cell renderer | ⚙️ Medium | new `ICellRendererAngularComp` |
| Collapsible scenario column groups | 🔧 Complex | migrate 24 flat cols → 8 `ColGroupDef`s, verify `columnGroupShow`, test with role-based col hide, update all Views |
| Font swap (Hanken Grotesk + IBM Plex Mono) | ⚙️ Medium | Google Fonts import + theme param + ::ng-deep on code/number cells |

**Recommended sequence:**
1. Theme params + ::ng-deep (all ✅ Cheap items) — one PR, no risk
2. Density toggle — one PR
3. Status + Step cell renderers — one PR each
4. Sub-grid flex + detail renderer SCSS — one PR
5. Collapsible column groups — last, careful PR with role-matrix testing
6. Frozen identity / Default View update — coordinate with backend

import {
    themeQuartz,
    themeBalham,
    themeMaterial,
    themeAlpine,
    Theme,
    colorSchemeLightWarm,
    colorSchemeLightCold,
    colorSchemeDarkWarm,
    colorSchemeDarkBlue,
  } from 'ag-grid-enterprise';

  // Custom Pink Theme
  const themePink: Theme = themeQuartz.withParams({
    backgroundColor: "rgb(249, 245, 227)",
    foregroundColor: "rgb(126, 46, 132)",
    headerTextColor:  "rgb(204, 245, 172)",
    headerBackgroundColor: "rgb(209, 64, 129)",
    oddRowBackgroundColor: "rgba(0, 0, 0, 0.03)",
    headerColumnResizeHandleColor: "rgb(126, 46, 132)",
    selectedRowBackgroundColor: "rgba(0, 255, 0, 0.1)"
  });

  // Export all themes in one place
  export const GRID_THEME_CONFIG: Record<string, Theme> = {
    // Default themes
    quartz: themeQuartz,
    balham: themeBalham,
    material: themeMaterial,
    alpine: themeAlpine,

    // Custom
    custom: themePink,

    // Color schemes
    quartzLightWarm: themeQuartz.withPart(colorSchemeLightWarm),
    quartzLightCold: themeQuartz.withPart(colorSchemeLightCold),
    quartzDarkWarm: themeQuartz.withPart(colorSchemeDarkWarm),
    quartzDarkBlue: themeQuartz.withPart(colorSchemeDarkBlue),
  };

export const RFQ_DETAIL_COLUMN_HEADERS_CONFIG: any = {
    columnDefs: getColumnDefs()
};

function getColumnDefs() {
    const commonDefaults = {
        filter: false,
        cellRenderer: null,
        hide: false,
        rowDrag: false,
        rowGroup: false,
        headerName: null,
        editable: true,
        cellEditor: null,
        headerStyle: {}
    };

    const addColumn = (
        field: string,
        colId: string,
        width: number,
        overrides: any = {}
    ) => {
        const { roles, ...rest } = overrides;
        return {
            field,
            colId,
            width,
            ...commonDefaults,
            ...rest,
            ...(roles !== undefined ? { context: { roles } } : {})
        };
    };

    return [
        addColumn("Name", "name", 220, {
            pinned: "left",
            sortable: true,
            editable: true,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("Price", "quote_price", 130, {
            sortable: true,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("CBM/pc", "cbm_pc", 130, {
            sortable: true,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("Note", "vendor_note", 320, {
            sortable: false,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("Lead Time (days)", "lead_time", 130, {
            sortable: true,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("Price Terms", "price_terms", 130, {
            sortable: true,
            cellEditor: "agSelectCellEditor",
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("FOB Country", "fob_country", 130, {
            sortable: true,
            cellEditor: "agSelectCellEditor",
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("FOB Port", "fob_port", 130, {
            sortable: true,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("Quote Date", "quote_date", 140, {
            hide: true,
            filter: "agDateColumnFilter",
            sortable: true,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        }),
        addColumn("Submit", "submite_btn", 160, {
            hide: true,
            editable: false,
            roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production', 'vendor']
        })
    ];
}

