input.new_string:
        addColumn("Status", "status", 120, {cellEditor: "autoCompelete", minWidth: 120, roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production'] }),
        addColumn("adam_fix", "adam_fix", 130, {hide: true, roles: ['admin', 'sourcing_manager', 'sales', 'designer', 'production'] }),
    ];

    // Scenario pricing cells get a family tint cellClass (SPEC_V2 §5e). Gen =
    // blue family, Lic = violet family; the always-visible "Price for Sales"
    // leaf gets an extra emphasis class. Applied here (not per addColumn) so the
    // family rule stays in one place and any new scenario leaf picks it up. The
    // matching CSS lives in rfq.component.scss (.ag-cell.scenario-*).
    const SCENARIO_COL_RE = /^(gen|lic)_(fob|poe|whse|mddp)_/;
    return columns.map((col: any) => {
        const match = SCENARIO_COL_RE.exec(col.colId);
        if (!match) return col;
        const family = match[1]; // 'gen' | 'lic'
        const isPriceForSales = col.colId.endsWith("_price_sales");
        const cellClass = isPriceForSales
            ? `scenario-${family} scenario-${family}--sales`
            : `scenario-${family}`;
        return { ...col, cellClass };
    });
}

