/**
 * Switch RFQ grid row density (SPEC_V2 §5i). Updates the grid rowHeight,
 * recalculates row heights so the change takes effect immediately, and
 * persists the choice to localStorage (restored in ngOnInit / onGridReady).
 */
setDensity(density: RfqDensity): void {
  this.density = density;
  const rowHeight = this.DENSITY_MAP[density].rowHeight;
  if (this.gridApi && !this.gridApi.isDestroyed()) {
    this.gridApi.setGridOption('rowHeight', rowHeight);
    this.gridApi.resetRowHeights();
  }
  try {
    localStorage.setItem('rfq:density', density);
  } catch {
    // localStorage may be unavailable (private mode); persistence is best-effort.
  }
}

/** Read the persisted density preference, defaulting to 'standard' (SPEC_V2 §5i). */
private loadDensityPreference(): RfqDensity {
  let saved: string | null = null;
  try {
    saved = localStorage.getItem('rfq:density');
  } catch {
    saved = null;
  }
  return saved === 'compact' || saved === 'comfortable' ? saved : 'standard';
}

