describe('row density toggle (SPEC_V2 §5i)', () => {
  beforeEach(() => localStorage.clear());

  test('defaults to standard density', () => {
    expect(createRfq().density).toBe('standard');
  });

  test('DENSITY_MAP maps each density to the spec row heights', () => {
    const comp = createRfq();
    expect(comp.DENSITY_MAP.compact.rowHeight).toBe(30);
    expect(comp.DENSITY_MAP.standard.rowHeight).toBe(36);
    expect(comp.DENSITY_MAP.comfortable.rowHeight).toBe(44);
  });

  test('setDensity updates state, grid rowHeight, resets heights, and persists', () => {
    const comp = createRfq();
    const setGridOption = jest.fn();
    const resetRowHeights = jest.fn();
    comp.gridApi = { setGridOption, resetRowHeights, isDestroyed: () => false } as any;

    comp.setDensity('compact');

    expect(comp.density).toBe('compact');
    expect(setGridOption).toHaveBeenCalledWith('rowHeight', 30);
    expect(resetRowHeights).toHaveBeenCalledTimes(1);
    expect(localStorage.getItem('rfq:density')).toBe('compact');
  });

  test('setDensity persists even when the grid API is not ready', () => {
    const comp = createRfq();
    comp.gridApi = undefined as any;
    expect(() => comp.setDensity('comfortable')).not.toThrow();
    expect(comp.density).toBe('comfortable');
    expect(localStorage.getItem('rfq:density')).toBe('comfortable');
  });

  test('persisted preference is read back (compact/comfortable honoured)', () => {
    const comp = createRfq();
    localStorage.setItem('rfq:density', 'comfortable');
    expect((comp as any).loadDensityPreference()).toBe('comfortable');
    localStorage.setItem('rfq:density', 'compact');
    expect((comp as any).loadDensityPreference()).toBe('compact');
  });

  test('invalid or missing preference falls back to standard', () => {
    const comp = createRfq();
    expect((comp as any).loadDensityPreference()).toBe('standard');
    localStorage.setItem('rfq:density', 'bogus');
    expect((comp as any).loadDensityPreference()).toBe('standard');
  });
});

