import { Component } from '@angular/core';
import { ICellRendererAngularComp } from 'ag-grid-angular';
import { ICellRendererParams } from 'ag-grid-community';
import { buildSnapshotTooltip } from '../helpers/price-sales-snapshot';

/**
 * Cell renderer for the 8 "Price for Sales" columns. Renders the formatted value and
 * sets a native `title` tooltip showing the duty rate and container price that were in
 * effect when the cell was last populated (read from the row's `price_sales_snapshots`).
 *
 * Why native `title` rather than the shared AG `customTooltip`: `tooltipShowMode` is a
 * grid-level option ('whenTruncated' here), with no per-column override. A native title
 * always shows on hover for just these columns, with zero impact on the global tooltip
 * behavior or the detail grid. Legacy rows without a snapshot get an empty title (no tooltip).
 */
@Component({
  selector: 'price-sales-snapshot-renderer',
  template: `<span [title]="tooltip">{{ display }}</span>`,
  standalone: false,
})
export class PriceSalesSnapshotRendererComponent implements ICellRendererAngularComp {
  display = '';
  tooltip = '';

  agInit(params: ICellRendererParams): void {
    this.update(params);
  }

  refresh(params: ICellRendererParams): boolean {
    this.update(params);
    return true;
  }

  private update(params: ICellRendererParams): void {
    this.display = params.valueFormatted ?? (params.value != null ? String(params.value) : '');
    const colId = params.colDef?.colId as string;
    const snapshot = colId ? params.data?.price_sales_snapshots?.[colId] : null;
    this.tooltip = buildSnapshotTooltip(snapshot);
  }
}

