import { Component } from '@angular/core';
import { ICellRendererAngularComp } from 'ag-grid-angular';
import { ICellRendererParams } from 'ag-grid-community';

export type StatusPillModifier = 'active' | 'draft' | 'inactive' | 'default';

/**
 * Map a raw status value to a known pill modifier (SPEC_V2 §5f).
 *
 * The spec markup interpolates the raw value into the class name; we map to a
 * fixed set instead so an unexpected status still renders as a styled (neutral)
 * pill rather than an unstyled span, and so arbitrary values can't inject class
 * names.
 */
export function statusPillModifier(value: unknown): StatusPillModifier {
  const v = (value == null ? '' : String(value)).trim().toLowerCase();
  if (v === 'active') return 'active';
  if (v === 'draft') return 'draft';
  if (v === 'inactive') return 'inactive';
  return 'default';
}

/**
 * Status cell renderer — coloured pill with a dot (SPEC_V2 §5f).
 * Registered as `statusPillRenderer` and wired to the `status` colDef.
 */
@Component({
  selector: 'status-pill-renderer',
  template: `
    @if (text) {
      <span class="status-pill status-pill--{{ modifier }}">
        <span class="status-pill__dot"></span>
        {{ text }}
      </span>
    }
  `,
  styleUrls: ['./status-pill-renderer.component.scss'],
  standalone: false,
})
export class StatusPillRendererComponent implements ICellRendererAngularComp {
  text = '';
  modifier: StatusPillModifier = 'default';

  agInit(params: ICellRendererParams): void {
    this.update(params);
  }

  refresh(params: ICellRendererParams): boolean {
    this.update(params);
    return true;
  }

  private update(params: ICellRendererParams): void {
    this.text = params.value != null && params.value !== '' ? String(params.value) : '';
    this.modifier = statusPillModifier(params.value);
  }
}

