import { Component } from '@angular/core';
import { ICellRendererAngularComp } from 'ag-grid-angular';
import { ICellRendererParams } from 'ag-grid-community';

export interface StepIndicatorView {
  shortLabel: string;
  dotColor: string;
}

const STEP_FALLBACK_COLOR = '#7b8a9a';

/** Step value → short label + dot colour mapping (SPEC_V2 §5g). Keys lowercased. */
const STEP_MAP: Record<string, StepIndicatorView> = {
  '@sales for details': { shortLabel: 'Sales detail', dotColor: '#6366f1' },
  '@sourcing': { shortLabel: 'Sourcing', dotColor: '#0ea5e9' },
  '@factories': { shortLabel: 'Factories', dotColor: '#f59e0b' },
  'px sent to sales': { shortLabel: 'Px → Sales', dotColor: '#10b981' },
  'px sent to cust': { shortLabel: 'Px → Customer', dotColor: '#22c55e' },
};

/**
 * Resolve a step value to its indicator view (SPEC_V2 §5g). Unknown non-empty
 * values are shown as-is with the neutral dot colour; empty values render nothing.
 */
export function stepIndicatorView(value: unknown): StepIndicatorView {
  if (value == null || value === '') {
    return { shortLabel: '', dotColor: STEP_FALLBACK_COLOR };
  }
  const key = String(value).trim().toLowerCase();
  return STEP_MAP[key] ?? { shortLabel: String(value), dotColor: STEP_FALLBACK_COLOR };
}

/**
 * Step cell renderer — coloured dot + short label (SPEC_V2 §5g). Subtler than the
 * status pill (no background chip). Registered as `stepIndicatorRenderer` and
 * wired to the `step` colDef.
 */
@Component({
  selector: 'step-indicator-renderer',
  template: `
    @if (shortLabel) {
      <span class="step-indicator">
        <span class="step-indicator__dot" [style.background]="dotColor"></span>
        {{ shortLabel }}
      </span>
    }
  `,
  styleUrls: ['./step-indicator-renderer.component.scss'],
  standalone: false,
})
export class StepIndicatorRendererComponent implements ICellRendererAngularComp {
  shortLabel = '';
  dotColor = STEP_FALLBACK_COLOR;

  agInit(params: ICellRendererParams): void {
    this.update(params);
  }

  refresh(params: ICellRendererParams): boolean {
    this.update(params);
    return true;
  }

  private update(params: ICellRendererParams): void {
    const view = stepIndicatorView(params.value);
    this.shortLabel = view.shortLabel;
    this.dotColor = view.dotColor;
  }
}

