import { describe, expect, test } from '@jest/globals';
import {
  StatusPillRendererComponent,
  statusPillModifier,
} from './status-pill-renderer.component';
import { ICellRendererParams } from 'ag-grid-community';

describe('statusPillModifier (SPEC_V2 §5f)', () => {
  test('maps known statuses (case/space-insensitive)', () => {
    expect(statusPillModifier('Active')).toBe('active');
    expect(statusPillModifier('  active ')).toBe('active');
    expect(statusPillModifier('Draft')).toBe('draft');
    expect(statusPillModifier('INACTIVE')).toBe('inactive');
  });

  test('falls back to default for unknown/empty values', () => {
    expect(statusPillModifier('Archived')).toBe('default');
    expect(statusPillModifier('')).toBe('default');
    expect(statusPillModifier(null)).toBe('default');
    expect(statusPillModifier(undefined)).toBe('default');
  });
});

describe('StatusPillRendererComponent', () => {
  const render = (value: unknown) => {
    const comp = new StatusPillRendererComponent();
    comp.agInit({ value } as ICellRendererParams);
    return comp;
  };

  test('agInit sets text and modifier for a known status', () => {
    const comp = render('Active');
    expect(comp.text).toBe('Active');
    expect(comp.modifier).toBe('active');
  });

  test('blank value renders no text', () => {
    expect(render('').text).toBe('');
    expect(render(null).text).toBe('');
  });

  test('refresh re-evaluates and returns true', () => {
    const comp = render('Active');
    const result = comp.refresh({ value: 'Draft' } as ICellRendererParams);
    expect(result).toBe(true);
    expect(comp.text).toBe('Draft');
    expect(comp.modifier).toBe('draft');
  });
});

