import { describe, expect, test } from '@jest/globals';
import { RFQ_COLUMN_HEADERS_CONFIG } from './rfq.grid.config';

function colById(colId: string) {
  const col = RFQ_COLUMN_HEADERS_CONFIG.columnDefs.find((c: { colId?: string }) => c.colId === colId);
  expect(col).toBeDefined();
  return col as Record<string, unknown>;
}

describe('RFQ_COLUMN_HEADERS_CONFIG (Ag-Grid)', () => {
  const { columnDefs } = RFQ_COLUMN_HEADERS_CONFIG;

  test('exports columnDefs array', () => {
    expect(Array.isArray(columnDefs)).toBe(true);
    expect(columnDefs.length).toBeGreaterThan(0);
  });

  test('every column has field, colId, and roles', () => {
    for (const def of columnDefs) {
      if (!def.field) {
        throw new Error(`field missing for colId=${def.colId}`);
      }
      if (!def.colId) {
        throw new Error(`colId missing for field=${def.field}`);
      }
      expect(Array.isArray((def as { context?: { roles?: unknown } }).context?.roles)).toBe(true);
    }
  });

  test('colId values are unique', () => {
    const ids = columnDefs.map((c: { colId: string }) => c.colId);
    expect(new Set(ids).size).toBe(ids.length);
  });

  test('Price Code column drives row grouping UI (pinned, group renderer)', () => {
    const price = colById('price_code');
    expect(price.pinned).toBe('left');
    expect(price.checkboxSelection).toBeUndefined();
    expect(price.cellRenderer).toBe('agGroupCellRenderer');
    expect(price.editable).toBe(false);
    expect(price.filter).toBe('agMultiColumnFilter');
  });

  test('Picture column disables filter and sorting for image cells', () => {
    const pic = colById('pic');
    expect(pic.filter).toBe(false);
    expect(pic.sortable).toBe(false);
  });

  test('RFQ Group column is the row group column', () => {
    const rfqGroup = colById('rfq_group');
    expect(rfqGroup.rowGroup).toBe(true);
    expect(rfqGroup.enableRowGroup).toBe(true);
    expect(rfqGroup.sortable).toBe(true);
    expect(rfqGroup.cellEditor).toBe('autoCompelete');
  });

  test('Date Modified column uses date filter and formatters', () => {
    const dateMod = colById('date_mod');
    expect(dateMod.filter).toBe('agDateColumnFilter');
    expect(dateMod.editable).toBe(false);
    expect(dateMod.valueFormatter).toBe('dateFormatter');
    expect(dateMod.comparator).toBe('dateComparator');
    expect(dateMod.sortable).toBe(true);
  });

  test('Step column set filter comparator orders workflow states', () => {
    const step = colById('step');
    expect(step.filter).toBe('agSetColumnFilter');
    const comparator = (step.filterParams as { comparator?: (a: string, b: string) => number })
      .comparator;
    expect(typeof comparator).toBe('function');
    expect(comparator!('@sales for details', '@sourcing')).toBeLessThan(0);
    expect(comparator!('@sourcing', 'px sent to sales')).toBeLessThan(0);
    expect(comparator!('For Later', null as unknown as string)).toBeGreaterThan(0);
  });

  test('expected hidden columns stay hidden by default', () => {
    const hiddenIds = [
      'item_label',
      'is_landed_cost_manual',
      'div',
      'carton_width',
      'carton_height',
      'agent',
      'adam_fix',
    ];
    for (const id of hiddenIds) {
      const hide = colById(id).hide;
      if (hide !== true) {
        throw new Error(`expected colId "${id}" to have hide: true, got ${String(hide)}`);
      }
    }
  });

  test('sort icons are present on representative columns', () => {
    const desc = colById('desc');
    const icons = desc.icons as { sortAscending?: string; sortDescending?: string };
    expect(icons.sortAscending).toContain('fa-sort-alpha-up');
    expect(icons.sortDescending).toContain('fa-sort-alpha-down');
  });

  test('Group column is limited to admin and sales roles', () => {
    const group = colById('group');
    expect((group as any).context?.roles).toEqual(['admin', 'sales']);
  });

  test('Date sent to factory column is visible, read-only, uses date filter', () => {
    const fu = colById('factory_updated');
    expect(fu.field).toBe('Factory_updated');
    expect(fu.headerName).toBe('Date Sent To Factory');
    expect(fu.hide).not.toBe(true);
    expect(fu.editable).toBe(false);
    expect(fu.filter).toBe('agDateColumnFilter');
    expect(fu.sortable).toBe(true);
    expect((fu as any).context?.roles).toContain('admin');
    expect((fu as any).context?.roles).toContain('sourcing_manager');
  });

  test('Date sent to factory column definition sits immediately after Step', () => {
    const ids = columnDefs.map((c: { colId?: string }) => c.colId);
    const stepIdx = ids.indexOf('step');
    const factoryIdx = ids.indexOf('factory_updated');
    expect(stepIdx).toBeGreaterThanOrEqual(0);
    expect(factoryIdx).toBe(stepIdx + 1);
  });

  test('column count matches RFQ grid definition (catch accidental drops)', () => {
    expect(columnDefs.length).toBe(70);
  });

  describe('scenario pricing cell tints (SPEC_V2 §5e)', () => {
    test('Gen scenario leaves get the scenario-gen family class', () => {
      expect(colById('gen_fob_sell_price').cellClass).toBe('scenario-gen');
      expect(colById('gen_poe_margin').cellClass).toBe('scenario-gen');
      expect(colById('gen_whse_sell_price').cellClass).toBe('scenario-gen');
    });

    test('Lic scenario leaves get the scenario-lic family class', () => {
      expect(colById('lic_fob_sell_price').cellClass).toBe('scenario-lic');
      expect(colById('lic_mddp_royalty').cellClass).toBe('scenario-lic');
      expect(colById('lic_whse_margin').cellClass).toBe('scenario-lic');
    });

    test('Price for Sales leaves get the emphasis variant class', () => {
      expect(colById('gen_fob_price_sales').cellClass).toBe('scenario-gen scenario-gen--sales');
      expect(colById('gen_mddp_price_sales').cellClass).toBe('scenario-gen scenario-gen--sales');
      expect(colById('lic_fob_price_sales').cellClass).toBe('scenario-lic scenario-lic--sales');
      expect(colById('lic_whse_price_sales').cellClass).toBe('scenario-lic scenario-lic--sales');
    });

    test('non-scenario columns are not tinted', () => {
      expect(colById('price_code').cellClass).toBeUndefined();
      expect(colById('landed_cost').cellClass).toBeUndefined();
      expect(colById('status').cellClass).toBeUndefined();
    });

    test('every scenario leaf (gen_*/lic_* term columns) receives a tint class', () => {
      const scenario = columnDefs.filter((c: { colId?: string }) =>
        /^(gen|lic)_(fob|poe|whse|mddp)_/.test(c.colId ?? ''),
      );
      expect(scenario.length).toBeGreaterThan(0);
      for (const col of scenario) {
        expect(typeof (col as { cellClass?: string }).cellClass).toBe('string');
        expect((col as { cellClass: string }).cellClass).toMatch(/^scenario-(gen|lic)/);
      }
    });
  });
});

