private loadDetailColumnHeaders(): Observable<any[]> {
  return this.itemService.getGridHeader({ grid_id: 'rfq_detail' }) as Observable<any[]>;
}

private configureDetailColumnHeaders(colHeaders: any[]): void {
  function formatNumber(number) {
    return Number.parseFloat(number).toString().replace(/(\d)(?=(\d{3})+(?!\d))/g, '$1,');
  }
  function formatDate(input) {
    if (input == null) return '';
    if (input.includes('-')) {
      const datePart = input.match(/\d+/g);
      const year = datePart[0].substring();
      const month = datePart[1];
      const day = datePart[2];
      return month + '/' + day + '/' + year;
    }
    return input;
  }
  function measurementFormatter(params) {
    if (params.value) {
      return formatNumber(params.value) + ' cm';
    }
  }
  // "2025-05-05" / "05/05/2025" -> "May 5 2025" for the re-quote tooltip.
  // Parses the parts manually to avoid timezone shifts from new Date(string).
  function formatQuotedDate(input) {
    if (input == null || input === '') return '';
    const months = ['January','February','March','April','May','June',
      'July','August','September','October','November','December'];
    const parts = String(input).match(/\d+/g);
    if (!parts || parts.length < 3) return String(input);
    let year, month, day;
    if (String(input).includes('-')) {
      // YYYY-MM-DD
      [year, month, day] = parts;
    } else {
      // MM/DD/YYYY
      [month, day, year] = parts;
    }
    const monthName = months[Number(month) - 1] || month;
    return `${monthName} ${Number(day)} ${year}`;
  }
