/** Merge the §5k sizing override (if any) onto a backend detail column def. */
export function applyDetailColumnSizing(col: any): any {
  if (!col || !col.colId) return col;
  const override = DETAIL_COLUMN_SIZING[col.colId];
  return override ? { ...col, ...override } : col;
}

