describe('applyDetailColumnSizing (SPEC_V2 §5k, hybrid detail-grid model)', () => {
  test('Note flexes to fill remaining width (live + config colIds)', () => {
    expect(applyDetailColumnSizing({ colId: 'note' })).toMatchObject({ flex: 1, minWidth: 200 });
    expect(applyDetailColumnSizing({ colId: 'vendor_note' })).toMatchObject({ flex: 1, minWidth: 200 });
  });

  test('Name is pinned left with a min width', () => {
    expect(applyDetailColumnSizing({ colId: 'name' })).toMatchObject({ pinned: 'left', minWidth: 180 });
  });

  test('Price is right-aligned with a min width (live + config colIds)', () => {
    expect(applyDetailColumnSizing({ colId: 'price' })).toMatchObject({ type: 'rightAligned', minWidth: 100 });
    expect(applyDetailColumnSizing({ colId: 'quote_price' })).toMatchObject({ type: 'rightAligned', minWidth: 100 });
  });

  test('override preserves existing colDef properties (merge, not replace)', () => {
    const col = { colId: 'note', field: 'Note', cellRenderer: 'x', valueFormatter: 'y' };
    const result = applyDetailColumnSizing(col);
    expect(result).toMatchObject({ colId: 'note', field: 'Note', cellRenderer: 'x', valueFormatter: 'y', flex: 1 });
  });

  test('non-overridden columns pass through untouched', () => {
    const col = { colId: 'lead_time', field: 'Lead Time', width: 110 };
    expect(applyDetailColumnSizing(col)).toEqual(col);
