describe('_saveViewStateToSession and restoreStateFromSession', () => {
  let comp: RfqComponent;
  let mockGridApi: any;

  beforeEach(async () => {
    TestBed.resetTestingModule();
    const itemServiceMock: Partial<itemService> = {
      getUserGridViews: jest.fn(() => of([])),
      getGridDefaultView: jest.fn(() => of(null)),
    };
    await TestBed.configureTestingModule({
      declarations: [RfqComponent],
      imports: [RouterTestingModule.withRoutes([])],
      providers: [
        { provide: itemService, useValue: itemServiceMock },
        { provide: MatDialog, useValue: { open: jest.fn() } },
        { provide: Meta, useValue: { updateTag: jest.fn() } },
        { provide: MatSnackBar, useValue: { open: jest.fn() } },
        rfqEquation,
        { provide: GridUISetupService, useValue: {} },
        { provide: ItemDetailService, useValue: {} },
        { provide: ConfigService, useValue: { get: jest.fn() } },
        { provide: LoaderService, useValue: { increment: jest.fn(), decrement: jest.fn() } },
        { provide: AuthService, useValue: { getUserFromToken: jest.fn(() => Promise.resolve(null)) } },
      ],
      schemas: [NO_ERRORS_SCHEMA],
    })
      .overrideComponent(RfqComponent, { set: { template: '<div></div>' } })
      .compileComponents();
    comp = TestBed.createComponent(RfqComponent).componentInstance;
    mockGridApi = {
      getColumnState: jest.fn(() => [{ colId: 'res', pinned: null }]),
      getFilterModel: jest.fn(() => ({})),
      setFilterModel: jest.fn(),
      applyColumnState: jest.fn(),
    };
    comp.gridApi = mockGridApi as any;
    sessionStorage.clear();
  });

  test('_saveViewStateToSession writes to sessionStorage regardless of canPersistGridState', () => {
    (comp as any).canPersistGridState = false;
    (comp as any)._saveViewStateToSession();
    const saved = JSON.parse(sessionStorage.getItem('gridState_rfq') || 'null');
    expect(saved?.columnState).toEqual([{ colId: 'res', pinned: null }]);
  });

  test('restoreStateFromSession clears session and returns early when hard reset flag is set', () => {
    sessionStorage.setItem('rfq_hard_reset_pending', '1');
