    expect(sessionStorage.getItem('rfq_hard_reset_pending')).toBeNull();
    expect(sessionStorage.getItem('gridState_rfq')).toBeNull();
  });

  test('restoreStateFromSession applies saved state when no hard reset flag', () => {
    const state = { columnState: [{ colId: 'res', pinned: null }], filterModel: {} };
    sessionStorage.setItem('gridState_rfq', JSON.stringify(state));
    (comp as any).restoreStateFromSession();
    expect(mockGridApi.applyColumnState).toHaveBeenCalledWith(
      expect.objectContaining({ applyOrder: true })
    );
  });
});

