/**
 * Collapsible pricing-scenario column groups (SPEC_V2 §1 / §5a, Step 5).
 *
 * The 24+ flat scenario leaf columns (Gen/Lic × FOB/POE/WHSE/MDDP × Sell/Margin/
 * Royalty/Price-for-Sales) are migrated into 8 `ColGroupDef`s — one per family ×
 * term. The "Price for Sales" leaf is always visible (the calm collapsed
 * default); Sell/Margin/Royalty leaves show only when the group is expanded
 * (`columnGroupShow: 'open'`).
 *
 * This runs on the assembled column defs (after role filtering + auto-formatters)
 * so each leaf keeps all its per-column wiring (headerClass tint, cellClass,
 * valueFormatter, cellRenderer, valueSetter, etc.). Children removed by role
 * filtering are simply absent — a group with only the sales leaf still renders.
 *
 * `groupId` is set so AG Grid persists each group's open/closed state as part of
 * column state (saved with the existing named-view layout). `marryChildren`
 * keeps a family's columns together. `headerGroupClass` drives the 2-family band
 * tint (CSS in rfq.component.scss).
 */

const SCENARIO_COL_RE = /^(gen|lic)_(fob|poe|whse|mddp)_/;

interface ScenarioFamily {
  prefix: 'gen' | 'lic';
  label: string;
  bandClass: string;
}

const FAMILIES: ScenarioFamily[] = [
  { prefix: 'gen', label: 'General', bandClass: 'group-band-gen' },
  { prefix: 'lic', label: 'Licensed', bandClass: 'group-band-lic' },
];

const TERMS: { key: string; label: string }[] = [
  { key: 'fob', label: 'FOB' },
  { key: 'poe', label: 'POE' },
  { key: 'whse', label: 'WHSE' },
  { key: 'mddp', label: 'MDDP' },
];

/** True when a column def is a scenario pricing leaf (by colId). */
export function isScenarioLeaf(col: any): boolean {
  return !!col && typeof col.colId === 'string' && SCENARIO_COL_RE.test(col.colId);
