export function buildScenarioGroups(columnDefs: any[]): any[] {
  if (!Array.isArray(columnDefs)) return columnDefs;

  const firstScenarioIdx = columnDefs.findIndex(isScenarioLeaf);
  if (firstScenarioIdx === -1) return columnDefs;

  const scenarioLeaves = columnDefs.filter(isScenarioLeaf);

  const groups: any[] = [];
  for (const fam of FAMILIES) {
    for (const term of TERMS) {
      const prefix = `${fam.prefix}_${term.key}_`;
      const children = scenarioLeaves
        .filter((c) => c.colId.startsWith(prefix))
