          columnGroupShow: c.colId.endsWith('_price_sales') ? undefined : 'open',
        }));
      if (children.length === 0) continue; // role filtered the whole family/term out
      groups.push({
        headerName: `${fam.label} · ${term.label}`,
        groupId: `${fam.prefix}_${term.key}`,
        marryChildren: true,
        headerGroupClass: fam.bandClass,
        children,
      });
