import { describe, expect, test } from '@jest/globals';
import { buildScenarioGroups, isScenarioLeaf } from './rfq-scenario-groups';

const FAMILIES = ['gen', 'lic'] as const;
const TERMS = ['fob', 'poe', 'whse', 'mddp'] as const;

/** Full admin scenario leaf set: gen has sell/margin/price_sales; lic adds royalty. */
function adminScenarioLeaves() {
  const cols: any[] = [];
  for (const fam of FAMILIES) {
    for (const term of TERMS) {
      if (fam === 'lic') cols.push({ colId: `${fam}_${term}_royalty`, headerClass: `group-header-${fam}-${term}` });
      cols.push({ colId: `${fam}_${term}_sell_price`, headerClass: `group-header-${fam}-${term}` });
      cols.push({ colId: `${fam}_${term}_margin`, headerClass: `group-header-${fam}-${term}` });
      cols.push({ colId: `${fam}_${term}_price_sales`, headerClass: `group-header-${fam}-${term}` });
    }
  }
  return cols;
}

/** Sales/designer see only the Price-for-Sales leaf of each family/term. */
function salesScenarioLeaves() {
  const cols: any[] = [];
  for (const fam of FAMILIES) {
    for (const term of TERMS) {
      cols.push({ colId: `${fam}_${term}_price_sales`, headerClass: `group-header-${fam}-${term}` });
    }
  }
  return cols;
}

const groupsOf = (defs: any[]) => defs.filter((d) => Array.isArray(d.children));

describe('isScenarioLeaf', () => {
  test('matches gen/lic family × term leaves only', () => {
    expect(isScenarioLeaf({ colId: 'gen_fob_sell_price' })).toBe(true);
    expect(isScenarioLeaf({ colId: 'lic_whse_royalty' })).toBe(true);
    expect(isScenarioLeaf({ colId: 'price_code' })).toBe(false);
    expect(isScenarioLeaf({ colId: 'landed_cost' })).toBe(false);
    expect(isScenarioLeaf({})).toBe(false);
    expect(isScenarioLeaf(null)).toBe(false);
  });
});

describe('buildScenarioGroups (SPEC_V2 §5a / Step 5)', () => {
  test('admin: produces 8 family×term groups in place of the flat leaves', () => {
    const input = [
      { colId: 'price_code' },
      ...adminScenarioLeaves(),
      { colId: 'note' },
    ];
    const out = buildScenarioGroups(input);
    const groups = groupsOf(out);

    expect(groups).toHaveLength(8);
    // surrounding columns preserved, groups spliced where the leaves were
    expect(out[0]).toEqual({ colId: 'price_code' });
    expect(out[out.length - 1]).toEqual({ colId: 'note' });
    expect(out.slice(1, 9)).toEqual(groups);

    const ids = groups.map((g) => g.groupId);
    expect(ids).toEqual([
      'gen_fob', 'gen_poe', 'gen_whse', 'gen_mddp',
      'lic_fob', 'lic_poe', 'lic_whse', 'lic_mddp',
    ]);
  });

  test('admin: group metadata and child visibility are correct', () => {
    const out = buildScenarioGroups(adminScenarioLeaves());
    const genFob = groupsOf(out).find((g) => g.groupId === 'gen_fob');
    expect(genFob.headerName).toBe('General · FOB');
    expect(genFob.headerGroupClass).toBe('group-band-gen');
    expect(genFob.marryChildren).toBe(true);

    // Gen group: sell + margin + price_sales (3 children)
    expect(genFob.children.map((c: any) => c.colId)).toEqual([
      'gen_fob_sell_price', 'gen_fob_margin', 'gen_fob_price_sales',
    ]);
    const show = Object.fromEntries(genFob.children.map((c: any) => [c.colId, c.columnGroupShow]));
    expect(show['gen_fob_price_sales']).toBeUndefined(); // always visible
    expect(show['gen_fob_sell_price']).toBe('open');
    expect(show['gen_fob_margin']).toBe('open');

    // Lic group carries royalty too, and gets the violet band
    const licFob = groupsOf(out).find((g) => g.groupId === 'lic_fob');
    expect(licFob.headerGroupClass).toBe('group-band-lic');
    expect(licFob.children).toHaveLength(4);
    expect(licFob.children.find((c: any) => c.colId === 'lic_fob_royalty').columnGroupShow).toBe('open');
  });

  test('sales/designer: 8 groups each with only the always-visible sales leaf', () => {
    const out = buildScenarioGroups(salesScenarioLeaves());
    const groups = groupsOf(out);
    expect(groups).toHaveLength(8);
    for (const g of groups) {
      expect(g.children).toHaveLength(1);
      expect(g.children[0].colId.endsWith('_price_sales')).toBe(true);
      expect(g.children[0].columnGroupShow).toBeUndefined();
    }
  });

  test('children preserve their original colDef wiring (merge, not replace)', () => {
    const leaf = {
      colId: 'gen_fob_price_sales',
      headerClass: 'group-header-gen-fob',
      cellClass: 'scenario-gen scenario-gen--sales',
      cellRenderer: 'priceSalesSnapshotRenderer',
    };
    const out = buildScenarioGroups([leaf]);
    const child = groupsOf(out)[0].children[0];
    expect(child).toMatchObject({
      colId: 'gen_fob_price_sales',
      headerClass: 'group-header-gen-fob',
      cellClass: 'scenario-gen scenario-gen--sales',
      cellRenderer: 'priceSalesSnapshotRenderer',
    });
  });

  test('roles with no scenario columns are returned unchanged', () => {
    const input = [{ colId: 'price_code' }, { colId: 'desc' }, { colId: 'status' }];
    expect(buildScenarioGroups(input)).toEqual(input);
  });

  test('does not mutate the input array', () => {
    const input = [{ colId: 'price_code' }, ...adminScenarioLeaves()];
    const copy = JSON.parse(JSON.stringify(input));
    buildScenarioGroups(input);
    expect(input).toEqual(copy);
  });
});

